//
// Runs against the master dev server at localhost:5177.
// window._gameEngine is set unconditionally in scene.js create() — no injection needed.
// The Phaser scene is accessible via character.sprite.scene.
//
// Bug: WALK_DIRS had { key: 'up', start: 0, end: 3 } — row 0 contains tiny placeholder
//      thumbnails, causing the walk-up animation to render with wrong-sized frames.
// Fix: Changed to { key: 'up', start: 48, end: 53 } — row 1 is the real up-walk frames.

const LOCAL_URL_MASTER = 'http://localhost:5177';

test.describe('FRG-204 (sprite-row): walk-up uses frames 48-53, not row 0 placeholders', () => {

  // ── TEST 5: walk-up Phaser animation is registered with frames 48-53 ─────────

  test('Amelia/Lucy/Ash walk_up animation uses frames 48-53 (row 1), not 0-5 (row 0 thumbnails)', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL_MASTER);
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 15_000 }
    );

    const results = await page.evaluate(() => {
      const engine = window._gameEngine;
      // Access the Phaser scene via the first character's sprite
      const scene = engine.characters[0]?.sprite?.scene;
      if (!scene) return { error: 'Phaser scene not accessible via sprite.scene' };

      const names = ['Amelia', 'Lucy', 'Ash'];
      const animResults = {};

      for (const name of names) {
        const anim = scene.anims.get(`${name}_walk_up`);
        if (!anim) { animResults[name] = { error: `${name}_walk_up animation not found` }; continue; }

        const frameNums = anim.frames.map(f => parseInt(f.frame.name, 10));
        const firstFrame = anim.frames[0];
        animResults[name] = {
          frameNums,
          frameCount:  frameNums.length,
          minFrame:    Math.min(...frameNums),
          maxFrame:    Math.max(...frameNums),
          // Frame dimensions: row 1 frames should be 48×96, row 0 was too small
          frameWidth:  firstFrame?.frame?.realWidth,
          frameHeight: firstFrame?.frame?.realHeight,
        };
      }

      return animResults;
    });

    console.log('Walk-up animation registration:', JSON.stringify(results, null, 2));

    for (const name of ['Amelia', 'Lucy', 'Ash']) {
      const r = results[name];
      expect(r?.error, `${name}_walk_up animation error`).toBeUndefined();

      // Core FRG-204 sprite-row fix: frames must be 48-53 (row 1), not 0-3 (row 0)
      expect(r.minFrame, `${name} walk-up first frame must be 48 (row 1 start, not row 0)`).toBe(48);
      expect(r.maxFrame, `${name} walk-up last frame must be 53 (row 1 end)`).toBe(53);
      expect(r.frameCount, `${name} walk-up must have 6 frames`).toBe(6);

      // Frame size sanity check: row 1 frames are 48×96 (full character height)
      expect(r.frameWidth,  `${name} walk-up frame width must be 48`).toBe(48);
      expect(r.frameHeight, `${name} walk-up frame height must be 96`).toBe(96);
    }
  });

  // ── TEST 6: all walk directions avoid row 0 placeholder frames ───────────────

  test('all 4 walk directions use correct non-placeholder frame ranges', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL_MASTER);
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 15_000 }
    );

    const results = await page.evaluate(() => {
      const engine = window._gameEngine;
      const scene  = engine.characters[0]?.sprite?.scene;
      if (!scene) return { error: 'Phaser scene not accessible' };

      const name = 'Amelia';
      const dirs = ['up', 'down', 'left', 'right'];
      const animData = {};

      for (const dir of dirs) {
        const anim = scene.anims.get(`${name}_walk_${dir}`);
        if (!anim) { animData[dir] = { error: 'not found' }; continue; }
        const frameNums = anim.frames.map(f => parseInt(f.frame.name, 10));
        animData[dir] = {
          frameNums,
          minFrame:   Math.min(...frameNums),
          maxFrame:   Math.max(...frameNums),
          frameCount: frameNums.length,
        };
      }

      return animData;
    });

    console.log('All walk direction frames:', JSON.stringify(results, null, 2));

    // Each direction must have 6 frames and must NOT use row 0 (frames 0–47 are thumbnails)
    for (const dir of ['up', 'down', 'left', 'right']) {
      const r = results[dir];
      expect(r?.error, `walk_${dir} animation error`).toBeUndefined();
      expect(r.frameCount, `walk_${dir} must have 6 frames`).toBe(6);
      expect(r.minFrame, `walk_${dir} must not use row 0 placeholder frames (frame < 48)`).toBeGreaterThanOrEqual(48);
    }

    // Exact expected frame ranges per direction (from WALK_DIRS in scene.js)
    expect(results.up.minFrame,    'walk-up starts at frame 48 (row 1)').toBe(48);
    expect(results.up.maxFrame,    'walk-up ends at frame 53').toBe(53);
    expect(results.down.minFrame,  'walk-down starts at frame 288 (row 6)').toBe(288);
    expect(results.down.maxFrame,  'walk-down ends at frame 293').toBe(293);
    expect(results.right.minFrame, 'walk-right starts at frame 144 (row 3)').toBe(144);
    expect(results.right.maxFrame, 'walk-right ends at frame 149').toBe(149);
    expect(results.left.minFrame,  'walk-left mirrors right (starts at 144 with flipX)').toBe(144);
    expect(results.left.maxFrame,  'walk-left mirrors right (ends at 149 with flipX)').toBe(149);
  });

  // ── TEST 7: walk-up animation plays with correct key during upward movement ──

  test('character playing walk-up uses Amelia_walk_up animation key during upward movement', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL_MASTER);
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 15_000 }
    );

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const amelia = engine.characters.find(c => c.name === 'Amelia');
      if (!amelia)         return { error: 'Amelia not found' };
      if (!amelia.sprite)  return { error: 'Amelia has no sprite' };

      const scene = amelia.sprite.scene;

      // Place Amelia at a walkable tile and issue an upward move
      amelia.tx = 8; amelia.ty = 7;
      amelia.prevTx = 8; amelia.prevTy = 7;
      amelia.action = 'idle';
      amelia.path   = [];
      amelia.moveProgress = 0;

      // Move up: ty decreases from 7 → 4 (all interior rows are walkable)
      const ok = amelia.moveTo(8, 4);
      if (!ok) return { error: 'moveTo(8,4) failed — path not found' };

      // After moveTo(), the walk animation should be playing
      const animKey = amelia.sprite.anims.currentAnim?.key;
      const facing  = amelia.facing;

      // Verify the registered frames for this animation via scene.anims
      const anim = scene.anims.get('Amelia_walk_up');
      const frameNums = anim ? anim.frames.map(f => parseInt(f.frame.name, 10)) : [];

      return {
        moveTo:    ok,
        facing,
        animKey,
        minFrame:  frameNums.length ? Math.min(...frameNums) : -1,
        maxFrame:  frameNums.length ? Math.max(...frameNums) : -1,
        frameCount: frameNums.length,
      };
    });

    console.log('Walk-up in-motion result:', JSON.stringify(result));

    expect(result.error, result.error).toBeUndefined();
    expect(result.moveTo, 'moveTo should succeed for upward path').toBe(true);
    expect(result.facing, 'Amelia should be facing up after moveTo(8,4)').toBe('up');
    expect(result.animKey, 'walk-up animation should be active').toBe('Amelia_walk_up');

    // FRG-204 sprite-row fix: the registered walk-up frames must be in 48-53 range
    expect(result.minFrame, 'walk-up frames start at 48 (not 0 — that was the bug)').toBe(48);
    expect(result.maxFrame, 'walk-up frames end at 53').toBe(53);
    expect(result.frameCount, 'walk-up has 6 frames').toBe(6);
  });
});

