    test.setTimeout(30_000);

    await page.goto(LOCAL_URL_MASTER_FACING);
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 15_000 }
    );

    const result = await page.evaluate(() => {
