      ash.tx  = 10; ash.ty  = 4;
      lucy.tx = 10; lucy.ty = 7;
      ash.path  = []; ash.moveProgress  = 0; ash.action  = 'idle';
      lucy.path = []; lucy.moveProgress = 0; lucy.action = 'idle';
      ash.facing  = 'right'; // wrong — should be corrected
      lucy.facing = 'left';  // wrong — should be corrected

      engine._startConversation(ash, lucy);

