    expect(result.ash.animKey).not.toBe('Ash_idle_anim');
    expect(result.lucy.animKey).not.toBe('Lucy_idle_anim');
    expect(result.ash.animKey,  'Ash plays Ash_idle_down during talk').toBe('Ash_idle_down');
    expect(result.lucy.animKey, 'Lucy plays Lucy_idle_up during talk').toBe('Lucy_idle_up');
  });

  // ── TEST 8: _playDirectionalIdle matches facing for all 4 directions ─────────

  test('_playDirectionalIdle plays {name}_idle_{facing} for each direction', async ({ page }) => {
    test.setTimeout(30_000);

