  // In Phaser 3, textures are stored as blob URLs after loading — compare the blobs.
  // Each independently loaded PNG produces a distinct blob URL even if file content differs.
  const offSrc = texOff.source?.[0]?.image?.src ?? texOff.source?.[0]?.src ?? null;
  const onSrc  = texOn.source?.[0]?.image?.src  ?? texOn.source?.[0]?.src  ?? null;

  // Draw each texture to a canvas and sample a pixel to confirm distinct pixel data
  // Use Phaser's built-in canvas snapshot approach via the texture frames
  const canvas = document.createElement('canvas');
  canvas.width = 48; canvas.height = 48;
  const ctx = canvas.getContext('2d');

  // Helper: get RGBA of pixel (0,0) from a Phaser texture
  function samplePixel(tex) {
    const src = tex.source?.[0]?.image;
    if (!src) return null;
    ctx.clearRect(0, 0, 48, 48);
    ctx.drawImage(src, 0, 0);
    const d = ctx.getImageData(0, 0, 48, 48).data;
    // Return first non-transparent pixel's color as a string
    for (let i = 0; i < d.length; i += 4) {
      if (d[i + 3] > 0) return `${d[i]},${d[i+1]},${d[i+2]},${d[i+3]}`;
    }
    return null;
  }

  const offPixel = samplePixel(texOff);
  const onPixel  = samplePixel(texOn);

  return {
    offKey:    texOff.key,
    onKey:     texOn.key,
    // Blob URLs will always differ between loads; just confirm they exist
    offHasSrc: !!offSrc,
    onHasSrc:  !!onSrc,
    srcsDiffer: offSrc !== onSrc,
    offPixel,
    onPixel,
    pixelsDiffer: offPixel !== onPixel,
  };
});

console.log('Phaser texture cache result:', JSON.stringify(result));

expect(result.error, result.error).toBeUndefined();

// Both textures must be present and have their own distinct keys
expect(result.offKey, 'stove_off texture key').toBe('stove_off');
expect(result.onKey,  'stove_on texture key').toBe('stove_on');

// Each texture must have a source (blob URL) — proves it was loaded
expect(result.offHasSrc, 'stove_off must have a loaded source image').toBe(true);
expect(result.onHasSrc,  'stove_on must have a loaded source image').toBe(true);

// The two textures must have been loaded from distinct sources (different blobs)
expect(result.srcsDiffer,
  'stove_off and stove_on must have been loaded from distinct source blobs'
).toBe(true);

// Pixel-level check: at least one pixel must differ between the two textures
expect(result.pixelsDiffer,
  `stove_off pixel (${result.offPixel}) and stove_on pixel (${result.onPixel}) ` +
  'must differ — identical pixel data would confirm the FRG-246 bug is not fixed'
).toBe(true);

