expect(result.onKey,  'stove_on texture key').toBe('stove_on');

// Each texture must have a source (blob URL) — proves it was loaded
expect(result.offHasSrc, 'stove_off must have a loaded source image').toBe(true);
expect(result.onHasSrc,  'stove_on must have a loaded source image').toBe(true);

// The two textures must have been loaded from distinct sources (different blobs)
expect(result.srcsDiffer,
