// ── FRG-246 (asset-diff fix): stove_on.png is a distinct visual asset ────────────
//
// Runs against master dev server at localhost:5177 (same server as tests 1-5 above).
// No injection needed; we fetch the PNG assets directly from the static server.
//
// Bug: stove_on.png was a byte-for-byte copy of stove_off.png, so toggling the
//      stove texture key had no visible effect — both states looked identical.
// Fix: stove_on.png was replaced with a new lit-stove image (distinct pixel data).

const LOCAL_URL_MASTER_SPRITE = 'http://localhost:5177';

test.describe('FRG-246 (asset-diff): stove_on.png is visually distinct from stove_off.png', () => {

  // ── TEST 6: file sizes differ ─────────────────────────────────────────────────

  test('stove_off.png and stove_on.png have different byte lengths', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL_MASTER_SPRITE);

    const result = await page.evaluate(async () => {
      const [offResp, onResp] = await Promise.all([
        fetch('/assets/sprites/stove_off.png'),
        fetch('/assets/sprites/stove_on.png'),
      ]);

      if (!offResp.ok) return { error: `stove_off.png fetch failed: ${offResp.status}` };
      if (!onResp.ok)  return { error: `stove_on.png fetch failed: ${onResp.status}`  };

      const [offBuf, onBuf] = await Promise.all([
        offResp.arrayBuffer(),
        onResp.arrayBuffer(),
      ]);

      return {
        stoveOffBytes:    offBuf.byteLength,
        stoveOnBytes:     onBuf.byteLength,
        differentSize:    offBuf.byteLength !== onBuf.byteLength,
      };
    });

    console.log('Stove PNG file sizes:', JSON.stringify(result));

    expect(result.error, result.error).toBeUndefined();
    expect(result.stoveOffBytes, 'stove_off.png must be non-empty').toBeGreaterThan(0);
    expect(result.stoveOnBytes,  'stove_on.png must be non-empty').toBeGreaterThan(0);
    expect(result.differentSize,
      `stove_off.png (${result.stoveOffBytes}B) and stove_on.png (${result.stoveOnBytes}B) ` +
      'must have different file sizes — identical sizes indicate the same asset'
    ).toBe(true);
  });

  // ── TEST 7: byte content differs in PNG header / IDAT chunks ─────────────────

  test('stove_off.png and stove_on.png have different byte content (not identical files)', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL_MASTER_SPRITE);

    const result = await page.evaluate(async () => {
      const [offResp, onResp] = await Promise.all([
        fetch('/assets/sprites/stove_off.png'),
        fetch('/assets/sprites/stove_on.png'),
      ]);

      if (!offResp.ok || !onResp.ok) {
        return { error: `PNG fetch failed: off=${offResp.status} on=${onResp.status}` };
      }

      const [offBuf, onBuf] = await Promise.all([
        offResp.arrayBuffer(),
        onResp.arrayBuffer(),
      ]);

      // Quick identity check: same byte length AND identical first 200 bytes = same file
      const SAMPLE = Math.min(200, offBuf.byteLength, onBuf.byteLength);
      const offBytes = new Uint8Array(offBuf, 0, SAMPLE);
      const onBytes  = new Uint8Array(onBuf,  0, SAMPLE);

      let diffCount = 0;
      for (let i = 0; i < SAMPLE; i++) {
        if (offBytes[i] !== onBytes[i]) diffCount++;
      }

      const sameLength = offBuf.byteLength === onBuf.byteLength;
      const noDiffs    = diffCount === 0;
      const filesAreIdentical = sameLength && noDiffs;

      return {
        stoveOffBytes:    offBuf.byteLength,
        stoveOnBytes:     onBuf.byteLength,
        sampleDiffBytes:  diffCount,
        filesAreIdentical,
      };
    });

    console.log('Stove PNG content comparison:', JSON.stringify(result));

    expect(result.error, result.error).toBeUndefined();
    expect(result.filesAreIdentical,
      `stove_off.png (${result.stoveOffBytes}B) and stove_on.png (${result.stoveOnBytes}B) ` +
      `must not be identical — FRG-246 bug was that stove_on.png was a copy of stove_off.png ` +
      `(${result.sampleDiffBytes} byte differences found in first 200 bytes)`
    ).toBe(false);
  });

  // ── TEST 8: Phaser loads both textures as distinct assets in the cache ────────

  test('Phaser texture cache holds distinct textures for stove_off and stove_on', async ({ page }) => {
    test.setTimeout(30_000);

    await page.goto(LOCAL_URL_MASTER_SPRITE);
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 15_000 }
    );

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const scene  = engine.characters[0]?.sprite?.scene;
      if (!scene) return { error: 'Phaser scene not accessible' };

      const texOff = scene.textures.get('stove_off');
      const texOn  = scene.textures.get('stove_on');

      if (!texOff || texOff.key === '__MISSING') return { error: 'stove_off texture not in Phaser cache' };
      if (!texOn  || texOn.key  === '__MISSING') return { error: 'stove_on texture not in Phaser cache'  };

      // In Phaser 3, each texture has a Source with the actual image element.
      // Identical files loaded under different keys may share or differ in source URL.
      const offSrc = texOff.source?.[0]?.image?.src ?? texOff.source?.[0]?.src ?? null;
      const onSrc  = texOn.source?.[0]?.image?.src  ?? texOn.source?.[0]?.src  ?? null;

      // Both textures must exist in the cache under their own keys
      return {
        offKey:  texOff.key,
        onKey:   texOn.key,
        offSrc,
        onSrc,
        // Width/height: if both were identical 48×48 PNGs they'd match;
        // distinct assets may differ in dimensions or at least in source URL.
        offWidth:  texOff.source?.[0]?.width,
        offHeight: texOff.source?.[0]?.height,
        onWidth:   texOn.source?.[0]?.width,
        onHeight:  texOn.source?.[0]?.height,
      };
    });

    console.log('Phaser texture cache result:', JSON.stringify(result));

    expect(result.error, result.error).toBeUndefined();

    // Both textures must be present and have their own distinct keys
    expect(result.offKey, 'stove_off texture key').toBe('stove_off');
    expect(result.onKey,  'stove_on texture key').toBe('stove_on');

    // Source URLs must differ (each key loads from its own PNG file)
    expect(result.offSrc, 'stove_off.png source URL').toMatch(/stove_off\.png/);
    expect(result.onSrc,  'stove_on.png source URL').toMatch(/stove_on\.png/);
    expect(result.offSrc,
      'stove_off and stove_on must load from different source files'
    ).not.toBe(result.onSrc);
  });
});

