  // Draw each texture to a canvas and compute a pixel-sum hash across the full image
  const canvas = document.createElement('canvas');
  canvas.width = 48; canvas.height = 48;
  const ctx = canvas.getContext('2d');

  // Helper: sum all R+G+B values across the 48×48 image as a simple hash
  function pixelSum(tex) {
    const src = tex.source?.[0]?.image;
    if (!src) return null;
    ctx.clearRect(0, 0, 48, 48);
    ctx.drawImage(src, 0, 0);
    const d = ctx.getImageData(0, 0, 48, 48).data;
    let sum = 0;
    for (let i = 0; i < d.length; i += 4) {
      sum += d[i] + d[i + 1] + d[i + 2];
    }
    return sum;
  }

  const offSum = pixelSum(texOff);
  const onSum  = pixelSum(texOn);

  return {
    offKey:    texOff.key,
    onKey:     texOn.key,
    offHasSrc: !!offSrc,
    onHasSrc:  !!onSrc,
    srcsDiffer: offSrc !== onSrc,
    offPixelSum: offSum,
    onPixelSum:  onSum,
    pixelSumDiffers: offSum !== onSum,
  };
});

